    @Throws(ClientException::class)
    @Suppress("ASSIGNED_BUT_NEVER_ACCESSED_VARIABLE")
    override suspend fun `dataPutPublic`(`data`: kotlin.ByteArray, `paymentMode`: kotlin.String) : DataPutPublicResult {
        return uniffiRustCallAsync(
