/**
 * Error type for client operations.
 */
sealed class ClientException: kotlin.Exception() {
    
    class InitializationFailed(
        
        val `reason`: kotlin.String
        ) : ClientException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class NetworkException(
        
        val `reason`: kotlin.String
        ) : ClientException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class PaymentException(
        
        val `reason`: kotlin.String
        ) : ClientException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class InvalidInput(
        
        val `reason`: kotlin.String
        ) : ClientException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class NotFound(
        
        val `reason`: kotlin.String
        ) : ClientException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class AlreadyExists(
        ) : ClientException() {
        override val message
            get() = ""
    }
    
    class WalletNotConfigured(
        ) : ClientException() {
        override val message
            get() = ""
    }
    
    class InternalException(
        
        val `reason`: kotlin.String
        ) : ClientException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<ClientException> {
        override fun lift(error_buf: RustBuffer.ByValue): ClientException = FfiConverterTypeClientError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeClientError : FfiConverterRustBuffer<ClientException> {
    override fun read(buf: ByteBuffer): ClientException {
        

        return when(buf.getInt()) {
            1 -> ClientException.InitializationFailed(
                FfiConverterString.read(buf),
                )
            2 -> ClientException.NetworkException(
                FfiConverterString.read(buf),
                )
            3 -> ClientException.PaymentException(
                FfiConverterString.read(buf),
                )
            4 -> ClientException.InvalidInput(
                FfiConverterString.read(buf),
                )
            5 -> ClientException.NotFound(
                FfiConverterString.read(buf),
                )
            6 -> ClientException.AlreadyExists()
            7 -> ClientException.WalletNotConfigured()
            8 -> ClientException.InternalException(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: ClientException): ULong {
        return when(value) {
            is ClientException.InitializationFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is ClientException.NetworkException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is ClientException.PaymentException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is ClientException.InvalidInput -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is ClientException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is ClientException.AlreadyExists -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ClientException.WalletNotConfigured -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is ClientException.InternalException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
        }
    }

    override fun write(value: ClientException, buf: ByteBuffer) {
        when(value) {
            is ClientException.InitializationFailed -> {
                buf.putInt(1)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is ClientException.NetworkException -> {
                buf.putInt(2)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is ClientException.PaymentException -> {
                buf.putInt(3)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is ClientException.InvalidInput -> {
                buf.putInt(4)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is ClientException.NotFound -> {
                buf.putInt(5)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is ClientException.AlreadyExists -> {
                buf.putInt(6)
                Unit
            }
            is ClientException.WalletNotConfigured -> {
                buf.putInt(7)
                Unit
            }
            is ClientException.InternalException -> {
                buf.putInt(8)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}





